class Solution {
    public String minWindow(String s, String t) {
        if (s == null || t == null) return "";
        Map<Character, Integer> tCount = new HashMap<>();
        for (char c : t.toCharArray()) tCount.put(c, tCount.getOrDefault(c, 0) + 1);
        int required = tCount.size();
        int left = 0, minLen = Integer.MAX_VALUE, minLeft = 0, minRight = 0;
        Map<Character, Integer> windowCount = new HashMap<>();
        int formed = 0;
        for (int right = 0; right < s.length(); right++) {
            char character = s.charAt(right);
            windowCount.put(character, windowCount.getOrDefault(character, 0) + 1);
            if (tCount.containsKey(character) && windowCount.get(character).equals(tCount.get(character))) formed++;
            while (left <= right && formed == required) {
                character = s.charAt(left);
                if (right - left + 1 < minLen) {
                    minLen = right - left + 1;
                    minLeft = left;
                    minRight = right;
                }
                windowCount.put(character, windowCount.get(character) - 1);
                if (tCount.containsKey(character) && windowCount.get(character) < tCount.get(character)) formed--;
                left++;
            }
        }
        return minLen == Integer.MAX_VALUE ? "" : s.substring(minLeft, minRight + 1);
    }
}
